mapper.select:
SELECT , p.patient_name, p.patient_no, p.gender, p.age, du.real_name AS doctor_name, ei.item_name, ei.item_code, ei.item_price, eu.real_name AS exam_doctor_name FROM exam_apply e LEFT JOIN patient p ON e.patient_id = p.patient_id LEFT JOIN sys_user du ON e.doctor_id = du.user_id LEFT JOIN exam_item ei ON e.item_id = ei.item_id LEFT JOIN sys_user eu ON e.exam_doctor_id = eu.user_id
AND e.status = #{status} AND e.patient_id = #{patientId} AND e.doctor_id = #{doctorId} AND e.exam_doctor_id = #{examDoctorId}
ORDER BY e.create_time DESC

mapper.update:
UPDATE exam_apply
status = #{status}, exam_doctor_id = #{examDoctorId}, exam_result = #{examResult}, exam_time = #{examTime}, clinical_info = #{clinicalInfo},
WHERE apply_id = #{applyId}
